code.perFrame:
zoom = 0.01;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
dec_med = pow(0.3, 30/fps);;
dec_slow = pow(0.99, 30/fps);;
beat = max(max(bass,mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (-2+avg+peak)) * ((time) > (t0+0.1));;
t0 = is_beat * beat + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat)%16;;
index2 = (index2 + is_beat*bnot(index))%2;;
q20 = avg;;
q21 = beat;;
q22 = peak;;
q23 = index;;
q24 = is_beat;;
q26 = bass_att + mid_att + treb_att;;
q27 = index+1;;
q28 = index2;;
q29 = ((index%2)-0.5)*2;;
k1 = is_beat*((index%2) == (0));;
p1 = k1*(p1+1) + (1-k1)*p1;;
p2 = dec_med * p2+(1-dec_med)*p1;;
rot = p2*3.1416/8;;
q1 = cos(rott);;
q2 = sin(rott);;
q3 = -q2;;
q4 = q1;;
//ds = max((q26-0.2),0);;
//step = step + ds/10;;
step = step + q24;;
p3 = p3*dec_slow + (1-dec_slow) * step;;
q30 = step;;
p4 = dec_slow*p4 + (1-dec_slow)*q27;;
q31 = p4;;
q12 = time -t0;;
monitor = q12;;
zoom = 1;;
rot = -0;;
warp = 0;;
dx = 0.00;;
wave_x = wave_x + 0.35*sin(time);;
wave_y = wave_y + 0.35*cos(time*1.21);;
wave_mystery = time/5*sin(q28/q24);;
wave_r = bass;;
wave_g = mid;;
wave_b = treb;

code.perVertex:
zoom = zoom - 0.125*sin(q28);;
rot = rot + 0.125*sin(q28+(time*0.369));;
dx = dx + q1*sin(time*0.96);;
dy = dy + q2*cos(time*0.85);
